171→    override fun getChangePayload(oldItem: PostListItemType, newItem: PostListItemType): Any? {
172→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
173→            /**
174→             * Suppresses the default animation if the progress has changed to prevent blinking as the upload progresses
175→             *
176→             * We don't need to use the payload in onBindViewHolder unless we want to. Passing a non-null value
177→             * suppresses the default ItemAnimator, which is all we need in this case.
178→             */
179→            if (oldItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
180→                newItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
181→                oldItem.data.progressBarUiState.progress != newItem.data.progressBarUiState.progress
182→            ) {
183→                return true
184→            }
185→        }
186→        return super.getChangePayload(oldItem, newItem)
187→    }
