199→    /**
200→     * Updates the data for the adapter while retaining visible item in certain cases.
201→     *
202→     * PagedList tries to keep the visible item by adding new items outside of the screen while modifying the scroll
203→     * position. In most cases, this works out great because it doesn't interrupt to the user. However, after a new
204→     * item is inserted at the top while the list is showing the very first items, it feels very weird to not have the
205→     * inserted item shown. For example, if a new draft is added there is no indication of it except for the flash
206→     * of the scroll bar which is not noticeable unless user is paying attention to it.
207→     *
208→     * In these cases, we try to keep the scroll position the same instead of keeping the visible item the same by
209→     * first saving the state and re-applying it after the data updates are completed. Since `PagedListAdapter` uses
210→     * bg thread to calculate the changes, we need to post the change in the bg thread as well so that it'll be applied
211→     * after changes are reflected.
212→     */
213→    private fun updatePagedListData(pagedListData: PagedPostList) {
214→        val recyclerViewState = recyclerView?.layoutManager?.onSaveInstanceState()
215→        postListAdapter.submitList(pagedListData)
216→        recyclerView?.post {
217→            (recyclerView?.layoutManager as? LinearLayoutManager)?.let { layoutManager ->
218→                if (layoutManager.findFirstVisibleItemPosition() < MAX_INDEX_FOR_VISIBLE_ITEM_TO_KEEP_SCROLL_POSITION) {
219→                    layoutManager.onRestoreInstanceState(recyclerViewState)
220→                }
221→            }
222→        }
223→    }
